import styled from 'styled-components';

export const HomePageContainer = styled.div`
    display: flex;
    justify-content: center;
    align-items: center;
    background-color: pink;
    gap: 5vw;

    .characters{
        background-color: lightblue
        width: 20vw
        height: 40
    }

    .spells{
        background-color:lightgreen
    }
`
